"""Chapter 4: Plate buckling direct stress EN 1993-1-5:2006."""

import math

# Tolerance for stress ratio (psi) comparisons to handle floating-point drift (e.g. 1.0001).
PSI_TOL = 0.0001

##### CHAPTER 4.4: Plate elements without longitudinal stiffeners (plate)  ######


def epsilon_parameter(fy: float) -> float:
    """Calculate the epsilon parameter based on the steel yield strength.

    BS EN 1993-1-5:2006. Section 4.4 (2)

    Args:
        fy (float): Yield strength of the steel in MPa.

    Returns:
        float: The epsilon value sqrt(235 / fy).
    """
    return math.sqrt(235.0 / fy)


def lambda_p(b_bar: float, t: float, epsilon: float, k_sigma: float) -> float:
    """Calculate the plate slenderness.

    BS EN 1993-1-5:2006. Section 4.4 (2)

    Args:
        b_bar (float): The appropriate width of the plate element in mm.
        t (float): The thickness of the plate in mm.
        epsilon (float): The material parameter from epsilon_parameter().
        k_sigma (float): The buckling factor from Table 4.1 or 4.2.

    Returns:
        float: The relative plate slenderness lambda_p.
    """
    return (b_bar / t) / (28.4 * epsilon * math.sqrt(k_sigma))


def rho_internal(lp: float, psi: float) -> float:
    """Calculate the reduction factor for internal compression elements.

    BS EN 1993-1-5:2006. Eq. (4.2)

    Args:
        lp (float): The relative plate slenderness (lambda_p).
        psi (float): The stress ratio (sigma2 / sigma1).

    Returns:
        float: The reduction factor rho.
    """
    limit = 0.5 + math.sqrt(0.085 - 0.055 * psi)

    if lp <= limit:
        return 1.0

    rho = (lp - 0.055 * (3 + psi)) / (lp**2)
    return min(rho, 1.0)


def rho_outstand(lp: float) -> float:
    """Calculate the reduction factor for outstand compression elements.

    BS EN 1993-1-5:2006. Eq. (4.3)

    Args:
        lp (float): The relative plate slenderness (lambda_p).

    Returns:
        float: The reduction factor rho.
    """
    # For lambda_p <= 0.748, rho = 1.0
    if lp <= 0.748:
        return 1.0

    # Eq. (4.3) for lambda_p > 0.748
    rho = (lp - 0.188) / (lp**2)
    return min(rho, 1.0)


def lambda_p_red(lp: float, sigma_com_ed: float, fy: float, gamma_m0: float = 1.0) -> float:
    """Calculate the reduced plate slenderness based on design stress.

    BS EN 1993-1-5:2006. Eq. (4.4)

    Args:
        lp (float): The relative plate slenderness (lambda_p).
        sigma_com_ed (float): Maximum design compressive stress in the element in MPa.
        fy (float): Yield strength of the steel in MPa.
        gamma_m0 (float): Partial factor for resistance. Default 1.0.

    Returns:
        float: The reduced plate slenderness lambda_p_red.
    """
    return lp * math.sqrt(sigma_com_ed / (fy / gamma_m0))


def k_sigma_table_4_1(psi: float) -> float:
    """Determine the buckling factor for internal compression elements.

    BS EN 1993-1-5:2006. Table 4.1

    Args:
        psi (float): Stress ratio (sigma2 / sigma1). Range: -3 <= psi <= 1. sigma1 is the maximum compressive stress.

    Returns:
        float: The buckling factor k_sigma.
    """
    if math.isclose(psi, 1.0, abs_tol=PSI_TOL):
        return 4.0
    if 1.0 > psi > 0.0:
        return 8.2 / (1.05 + psi)
    if math.isclose(psi, 0.0, abs_tol=PSI_TOL):
        return 7.81
    if 0.0 > psi > -1.0:
        return 7.81 - 6.29 * psi + 9.78 * (psi**2)
    if math.isclose(psi, -1.0, abs_tol=PSI_TOL):
        return 23.9
    if -1.0 > psi >= -3.0:
        return 5.98 * (1 - psi) ** 2
    raise ValueError('Stress ratio psi out of range for Table 4.1 (-3 to 1).')


def k_sigma_table_4_2(psi: float, max_stress_at_supported_edge: bool = True) -> float:
    """Determine the buckling factor for outstand compression elements.

    BS EN 1993-1-5:2006. Table 4.2

    Args:
        psi (float): Stress ratio (sigma2 / sigma1). Range: -3 <= psi <= 1.
        max_stress_at_supported_edge (bool): True if sigma1 is at the supported edge.
            False if sigma1 is at the free edge.

    Returns:
        float: The buckling factor k_sigma.
    """
    if max_stress_at_supported_edge:
        # Values from bottom half of Table 4.2
        if math.isclose(psi, 1.0, abs_tol=PSI_TOL):
            return 0.43
        if 1.0 > psi > 0.0:
            return 0.578 / (psi + 0.34)
        if math.isclose(psi, 0.0, abs_tol=PSI_TOL):
            return 1.70
        if 0.0 > psi > -1.0:
            return 1.7 - 5 * psi + 17.1 * (psi**2)
        if math.isclose(psi, -1.0, abs_tol=PSI_TOL):
            return 23.8
        raise ValueError('Stress ratio psi out of range for Table 4.2.')
    # Values from top half of Table 4.2
    if 1.0 > psi >= -3:
        return 0.57 - 0.21 * psi + 0.07 * (psi**2)
    raise ValueError('Stress ratio psi out of range for Table 4.2.')


def beff_internal(rho: float, b_bar: float, psi: float) -> dict:
    """Calculate the effective width and distribution for internal elements.

    BS EN 1993-1-5:2006. Table 4.1

    Args:
        rho (float): Reduction factor for plate buckling.
        b_bar (float): Gross width of the internal element (e.g., hw for webs).
        psi (float): Stress ratio (sigma2 / sigma1).

    Returns:
        dict: A dictionary containing 'beff', 'be1', and 'be2' in mm.
    """
    if math.isclose(psi, 1.0, abs_tol=PSI_TOL):
        beff = rho * b_bar
        be1 = 0.5 * beff
        be2 = 0.5 * beff
    elif 1.0 > psi >= 0.0:
        beff = rho * b_bar
        be1 = (2 / (5 - psi)) * beff
        be2 = beff - be1
    elif psi < 0.0:
        # For psi < 0, compression zone width bc = b_bar / (1 - psi)
        bc = b_bar / (1 - psi)
        beff = rho * bc
        be1 = 0.4 * beff
        be2 = 0.6 * beff
    else:
        raise ValueError('Psi must be <= 1.0')

    return {'beff': beff, 'be1': be1, 'be2': be2}


def beff_outstand(rho: float, c: float, psi: float) -> float:
    """Calculate the effective width for outstand compression elements.

    BS EN 1993-1-5:2006. Table 4.2

    Args:
        rho (float): Reduction factor for plate buckling.
        c (float): Gross width of the outstand element.
        psi (float): Stress ratio (sigma2 / sigma1).

    Returns:
        float: The effective width beff in mm.
    """
    if math.isclose(psi, 1.0, abs_tol=PSI_TOL) or (1.0 > psi >= 0.0):
        return rho * c
    if psi < 0.0:
        # For psi < 0, bc = c / (1 - psi)
        bc = c / (1 - psi)
        return rho * bc
    raise ValueError('Psi must be <= 1.0')


### CHAPTER 4.5 Stiffened plate elements with longitudinal stiffeners (whole panel)  ###


def Ac_eff_stiffened(rho_c: float, Ac_eff_loc: float, sum_b_edge_eff_t: float) -> float:
    """Calculate the effective area of the compression zone of a stiffened plate.

    BS EN 1993-1-5:2006. Eq. (4.5)

    Args:
        rho_c (float): Reduction factor for overall buckling.
        Ac_eff_loc (float): Effective section area for local buckling of
            stiffeners and subpanels (calculated via Eq. 4.6).
        sum_b_edge_eff_t (float): Area of the effective parts supported by
            adjacent plate elements (sum of b_edge_eff * t).

    Returns:
        float: The effective area Ac,eff in mm2.
    """
    return rho_c * Ac_eff_loc + sum_b_edge_eff_t


def Ac_eff_loc_stiffened(Asl_eff: float, rho_loc_list: list, bc_loc_list: list, t: float) -> float:
    """Calculate the effective section area for local buckling of the stiffened plate.

    BS EN 1993-1-5:2006. Eq. (4.6)

    Args:
        Asl_eff (float): Sum of effective sections of all longitudinal
            stiffeners in the compression zone.
        rho_loc_list (list): List of reduction factors rho_loc for each subpanel.
        bc_loc_list (list): List of widths of the compressed part of each subpanel.
        t (float): Thickness of the plate in mm.

    Returns:
        float: The effective area Ac,eff,loc in mm2.
    """
    subpanels_area = sum(rho * bc * t for rho, bc in zip(rho_loc_list, bc_loc_list))
    return Asl_eff + subpanels_area


### CHAPTER 4.5.2 Plate type behaviour  ###


def lambda_p_equivalent(beta_Ac: float, fy: float, sigma_cr_p: float) -> float:
    """Calculate the relative plate slenderness of the equivalent orthotropic plate.

    BS EN 1993-1-5:2006. Eq. (4.7)

    Args:
        beta_Ac (float): Area reduction factor (Ac,eff,loc / Ac).
        fy (float): Yield strength of the steel in MPa.
        sigma_cr_p (float): Elastic critical plate buckling stress in MPa.

    Returns:
        float: The relative plate slenderness lambda_p_bar.
    """
    return math.sqrt((beta_Ac * fy) / sigma_cr_p)


### CHAPTER 4.5.3 Column type behaviour  ###


def sigma_cr_c_unstiffened(E: float, t: float, a: float, nu: float = 0.3) -> float:
    """Calculate the elastic critical column buckling stress of an unstiffened plate.

    BS EN 1993-1-5:2006. Eq. (4.8)

    Args:
        E (float): Modulus of elasticity in MPa.
        t (float): Thickness of the plate in mm.
        a (float): Spacing between transverse stiffeners in mm.
        nu (float, optional): Poisson's ratio. Default 0.3.

    Returns:
        float: The elastic critical column buckling stress sigma_cr,c in MPa.
    """
    return (math.pi**2 * E * t**2) / (12 * (1 - nu**2) * a**2)


def sigma_cr_sl_stiffened(E: float, Isl_1: float, Asl_1: float, a: float) -> float:
    """Calculate the elastic critical column buckling stress of the stiffener.

    BS EN 1993-1-5:2006. Eq. (4.9)

    Args:
        E (float): Modulus of elasticity in MPa.
        Isl_1 (float): Second moment of area of the gross cross section of
            the stiffener and adjacent parts of the plate in mm4.
        Asl_1 (float): Gross cross-sectional area of the stiffener and
            adjacent parts of the plate in mm2.
        a (float): Spacing between transverse stiffeners in mm.

    Returns:
        float: The buckling stress sigma_cr,sl in MPa.
    """
    return (math.pi**2 * E * Isl_1) / (Asl_1 * a**2)


def lambda_column(fy: float, sigma_cr_c: float, stiffened: bool = False, beta_Ac: float = None) -> float:
    """Calculate the relative column slenderness for unstiffened and stiffened plates.

    BS EN 1993-1-5:2006. Eq. (4.10) or (4.11)

    Args:
        fy (float): Yield strength of the steel in MPa.
        sigma_cr_c (float): Elastic critical column buckling stress in MPa.
        stiffened (bool): True if the plate is stiffened, False if it is unstiffened.
        beta_Ac (float): Area reduction factor (Asl,1,eff / Asl,1) if stiffened plates.

    Returns:
        float: The relative column slenderness lambda_c_bar.
    """
    if stiffened:
        return math.sqrt((beta_Ac * fy) / sigma_cr_c)
    return math.sqrt(fy / sigma_cr_c)


# 4.5.4 interacion column-plate  ###


def rho_c_interaction(rho: float, chi_c: float, sigma_cr_p: float, sigma_cr_c: float) -> float:
    """Calculate the final reduction factor by interpolation between plate and column buckling.

    BS EN 1993-1-5:2006. Eq. (4.13)

    Args:
        rho (float): Reduction factor due to plate buckling.
        chi_c (float): Reduction factor due to column buckling.
        sigma_cr_p (float): Elastic critical plate buckling stress in MPa.
        sigma_cr_c (float): Elastic critical column buckling stress in MPa.

    Returns:
        float: The final reduction factor rho_c.
    """
    # Calculate the interpolation parameter xi (Eq. 4.13)
    xi = (sigma_cr_p / sigma_cr_c) - 1.0

    # Apply limits: 0 <= xi <= 1
    xi = max(0.0, min(1.0, xi))

    # Final reduction factor rho_c (Eq. 4.13)
    return (rho - chi_c) * xi * (2.0 - xi) + chi_c
